def sanitize_sensitive_data(data, fields_to_sanitize=['password', 'token', 'api_key', 'secret', 'auth_token', 'authorization']):
    """
    Sanitize sensitive data by masking specified fields.
    This is a security best practice - DO NOT log sensitive data in production.
    """
    if not isinstance(data, dict):
        return data
    
    sanitized = data.copy()
    for key in sanitized:
        if any(sensitive in key.lower() for sensitive in fields_to_sanitize):
            if sanitized[key]:
                sanitized[key] = '***REDACTED***'
    return sanitized


def log_request_info():
    """Log incoming request information with security considerations"""
    try:
        request_data = {
            'timestamp': datetime.utcnow().isoformat(),
            'method': request.method,
            'url': request.url,
            'endpoint': request.endpoint,
            'remote_addr': request.remote_addr,
            'user_agent': str(request.user_agent),
        }
        
        # Log headers (sanitize sensitive headers)
        headers = dict(request.headers)
        sanitized_headers = sanitize_sensitive_data(headers)
        request_data['headers'] = sanitized_headers
        
        # Log request body (sanitize sensitive fields)
        if request.is_json:
            body = request.get_json()
            sanitized_body = sanitize_sensitive_data(body)
            request_data['body'] = sanitized_body
        elif request.form:
            form_data = request.form.to_dict()
            sanitized_form = sanitize_sensitive_data(form_data)
            request_data['form_data'] = sanitized_form
        
        # Log query parameters
        if request.args:
            request_data['query_params'] = dict(request.args)
        
        # Log user information if available
        if hasattr(g, 'user'):
            request_data['user'] = {
                'id': getattr(g.user, 'id', None),
                'username': getattr(g.user, 'username', None),
                'email': getattr(g.user, 'email', None)
            }
        
        app.logger.info(f"REQUEST: {json.dumps(request_data, indent=2)}")
        
    except Exception as e:
        app.logger.error(f"Error logging request info: {str(e)}")


def log_response_info(response):
    """Log response information"""
    try:
        response_data = {
            'timestamp': datetime.utcnow().isoformat(),
            'status_code': response.status_code,
            'content_type': response.content_type,
        }
        
        if response.is_json:
            try:
                response_data['body'] = response.get_json()
            except:
                response_data['body'] = 'Unable to parse JSON'
        
        app.logger.info(f"RESPONSE: {json.dumps(response_data, indent=2)}")
        
    except Exception as e:
        app.logger.error(f"Error logging response info: {str(e)}")
    
    return response


@app.before_request
def before_request():
    """Execute before each request"""
    log_request_info()


@app.after_request
def after_request(response):
    """Execute after each request"""
    return log_response_info(response)


@app.errorhandler(Exception)
def handle_exception(e):
    """Handle all exceptions and log them"""
    error_data = {
        'timestamp': datetime.utcnow().isoformat(),
        'error_type': type(e).__name__,
        'error_message': str(e),
        'traceback': traceback.format_exc(),
        'request_url': request.url,
        'request_method': request.method,
        'remote_addr': request.remote_addr
    }
    
    app.logger.error(f"EXCEPTION: {json.dumps(error_data, indent=2)}")
    
    return jsonify({
        'error': 'Internal server error',
        'message': str(e)
    }), 500


def require_auth(f):
    """Authentication decorator with secure logging"""
    @wraps(f)
    def decorated_function(*args, **kwargs):
        auth_header = request.headers.get('Authorization')
        
        if not auth_header:
            app.logger.warning(f"Authentication failed: No authorization header provided from {request.remote_addr}")
            return jsonify({'error': 'No authorization header'}), 401
        
        # In production, NEVER log actual tokens
        # This is a sanitized version for security
        app.logger.info(f"Authentication attempt from {request.remote_addr} - Token: ***REDACTED***")
        
        # Simulate token validation
        if auth_header != 'Bearer valid_token':
            app.logger.warning(f"Authentication failed: Invalid token from {request.remote_addr}")
            return jsonify({'error': 'Invalid token'}), 401
        
        app.logger.info(f"Authentication successful from {request.remote_addr}")
        return f(*args, **kwargs)
    
    return decorated_function


